ALL_COMPETITIONS_DICT = {c.competition_id: c for c in ALL_COMPETITIONS_LIST}


class BenchmarkTaskIds(str, ListableEnum):
    ALL = "all"
    BASIC_TAB = "basic_tab"
    BENCHMARK_AGENT_K_V1_1 = "benchmark_agent_k_v1_1"


def filter_img_task_id(competition_id: CompetitionID) -> bool:
    """ If competition id  corresponds to a competition with image inputs and not text inputs """
    competition = ALL_COMPETITIONS_DICT[competition_id]
    return DataType.IMG in competition.input_types and DataType.TXT not in competition.input_types


def filter_tab_task_id(competition_id: CompetitionID) -> bool:
    """ If competition id  corresponds to a competition with only tabular inputs"""
    competition = ALL_COMPETITIONS_DICT[competition_id]
    return competition.input_types == {DataType.TAB}


def filter_txt_task_id(competition_id: CompetitionID) -> bool:
    """ If competition id  corresponds to a competition with text inputs and not image inputs """
    competition = ALL_COMPETITIONS_DICT[competition_id]
    return DataType.TXT in competition.input_types and DataType.IMG not in competition.input_types


def filter_submission_file_upload(competition_id: CompetitionID) -> bool:
    """ filter competitions with file upload submission type """
    competition = ALL_COMPETITIONS_DICT[competition_id]
    return competition.submission_mode == SubmissionMode.FILE_UPLOAD


def filter_submission_code_notebook(competition_id: CompetitionID) -> bool:
    """ filter competitions with code notebook submission type """
    competition = ALL_COMPETITIONS_DICT[competition_id]
    return competition.submission_mode == SubmissionMode.CODE_NOTEBOOK


def filter_submission_notebook_file_upload(competition_id: CompetitionID) -> bool:
    """ filter competitions with notebook file upload submission type """
    competition = ALL_COMPETITIONS_DICT[competition_id]
    return competition.submission_mode == SubmissionMode.NOTEBOOK_FILE_UPLOAD


class TaskBenchmark(BaseModel):
    benchmark_task_id: BenchmarkTaskIds
    task_filter: Callable[[Competition], bool]

    @property
    def tasks(self) -> list[CompetitionID]:
        return [c.competition_id for c in ALL_COMPETITIONS_LIST if self.task_filter(c)]

    def get_task_subset(self, task_filtr: Callable[[CompetitionID], bool]) -> list[CompetitionID]:
        return [task for task in self.tasks if task_filtr(task)]

    def get_tab_tasks(self) -> list[CompetitionID]:
        return self.get_task_subset(task_filtr=filter_tab_task_id)

    def get_img_tasks(self) -> list[CompetitionID]:
        return self.get_task_subset(task_filtr=filter_img_task_id)

    def get_txt_tasks(self) -> list[CompetitionID]:
        return self.get_task_subset(task_filtr=filter_txt_task_id)

    def get_submission_file_upload_tasks(self) -> list[CompetitionID]:
        return self.get_task_subset(task_filtr=filter_submission_file_upload)

    def get_submission_code_notebook_tasks(self) -> list[CompetitionID]:
        return self.get_task_subset(task_filtr=filter_submission_code_notebook)

    def get_submission_notebook_file_upload_tasks(self) -> list[CompetitionID]:
        return self.get_task_subset(task_filtr=filter_submission_notebook_file_upload)


