def get_competition_id_list(list_id: BenchmarkTaskIds | str) -> list[CompetitionID]:
    if not isinstance(list_id, BenchmarkTaskIds) and isinstance(list_id, str) and list_id in BenchmarkTaskIds.list():
        list_id = BenchmarkTaskIds.get_enum_element(value=list_id)

    benchmark_agent_k_v1_1 = TaskBenchmark(
        benchmark_task_id=BenchmarkTaskIds.BENCHMARK_AGENT_K_V1_1,
        task_filter=_filter_competitions_agent_k_v1_1
    )

    if list_id == BenchmarkTaskIds.BENCHMARK_AGENT_K_V1_1:
        return benchmark_agent_k_v1_1.tasks
    elif list_id == BenchmarkTaskIds.BASIC_TAB:
        return [
            CompetitionID.TABULAR_PLAYGROUND_SERIES_AUG_2021,
            CompetitionID.PLAYGROUND_SERIES_S3E14,
            CompetitionID.PLAYGROUND_SERIES_S4E3
        ]
    elif list_id == BenchmarkTaskIds.ALL:
        return list(CompetitionID)
    else:
        raise ValueError(list_id)


def get_competitions_from_ids(lis_of_ids: list[CompetitionID]) -> list[Competition]:
    return [ALL_COMPETITIONS_DICT[competition_id] for competition_id in lis_of_ids]


def get_competitions(list_id: BenchmarkTaskIds) -> list[Competition]:
    competition_ids = get_competition_id_list(list_id=list_id)
    return [ALL_COMPETITIONS_DICT[competition_id] for competition_id in competition_ids]


