def parsergb(color: str) -> str:
    """

    Args:
        color: the color property for a kaggle competition type or the competition type

    Returns:
        a color string to be used in latex

    """
    return color.replace("(", "{").replace(")", "}")


def clean_task_string(task_str: str) -> str:
    """

    Args:
        task_str: name of the task

    Returns:
        a post processed string to comply with the late syntax
    """
    return task_str.replace(" ", "").replace("&", "").replace("-", "")


def competition_table(
        competitions: list,
        leaderboards: dict
) -> str:
    """
    Args:
        competitions: contains the competitions to be added in the table
        leaderboards: kaggle leaderboards for each competition

    Returns:
        Latex code to create a table with the competition details
    """

    latex_lines = []

    kaggle_competition_type_aux = KaggleCompetitionTypeAux.get_kaggle_competition_types()

    # Generate tikz icon commands for each task type
    for comp_type, aux in kaggle_competition_type_aux.items():
        color = parsergb(aux.circle_colors[-1])
        cmd = rf"\newcommand{{\{clean_task_string(comp_type)}}}{{%" + "\n" + \
              rf"  \begin{{tikzpicture}}[baseline=-0.5ex]" + "\n" + \
              rf"    \node[circle, fill={color}, text=white, inner sep=0pt, minimum size=1.2em, text width=1.3em, align=center] " \
              + rf"{{\tiny {{\textbf{{{aux.short_text[-1]}}}}}}};" + "\n" + \
              rf"  \end{{tikzpicture}}%" + "\n" + rf"}}"
        latex_lines.append(cmd)

    competition_type_aux = CompetitionTypeAux.get_competition_types()

    for comp_type, aux in competition_type_aux.items():
        if comp_type != CompetitionType.REGRESSION_AND_BINARY_CLASSIFICATION:
            color = parsergb(aux.circle_colors[-1])
            cmd = rf"\newcommand{{\{clean_task_string(comp_type)}}}{{%" + "\n" + \
                  rf"  \begin{{tikzpicture}}[baseline=-0.5ex]" + "\n" + \
                  rf"    \node[circle, fill={color}, text=white, inner sep=0pt, minimum size=1.2em, text width=1.3em, align=center] " \
                  + rf"{{\tiny {{\textbf{{{aux.short_text[-1]}}}}}}};" + "\n" + \
                  rf"  \end{{tikzpicture}}%" + "\n" + rf"}}"
            latex_lines.append(cmd)

    # Prepare table rows
    competition_data = []
    for comp in competitions:
        comp_type = comp.kaggle_competition_type.value if comp.kaggle_competition_type.value != "getting_started" else "gettingstarted"
        competition_data.append(
            {
                "CompetitionID": comp.competition_id.value,
                "TaskType": clean_task_string(comp.competition_type.value),
                "CompetitionType": comp_type,
                "Modality": ','.join(t.value.capitalize() for t in comp.input_types),
                "MaxSubmissions": comp.max_selected_submissions,
                "NumTeams": len(leaderboards.get(comp.competition_id))
            }
        )

    if not competition_data:
        return "\n".join(latex_lines)  # no data

    # Build longtable
    cols = ["CompetitionID", "TaskType", "CompetitionType", "Modality", "MaxSubmissions", "NumTeams"]
    colspec = ["p{5cm}", "c", "c", "c", "c", "c"]

    headers = [
        r"\textbf{Competition}",
        r"\makecell{\textbf{Competition}\\\textbf{Type}}",
        r"\makecell{\textbf{Kaggle}\\\textbf{Category}}",
        r"\textbf{Modality}",
        r"\makecell{\textbf{\#Select}\\\textbf{Subs}}",
        r"\makecell{\textbf{\#Teams}}"
    ]

    latex_lines += [
        r"\begin{table}[H]",
        r"\centering",
        r"\caption{\textbf{Symbols associated to competition types and competition categories on Kaggle.}}",
        r"\label{tab:symbol-legend}",
        r"\begin{tabular}{cc|cc}",
        r"\toprule",
        r"\textbf{Competition Type} & \textbf{Meaning} & \textbf{Kaggle Category} & \textbf{Meaning} \\",
        r"\midrule",
        r"\Regression & Regression & \gettingstarted & Getting Started \\",  # TODO: don't hard-code that
        r"\BinaryClassification & Binary Classification & \playground & Playground \\",
        r"\MulticlassClassification & Multiclass Classification & \featured & Featured \\",
        r"\MultitargetRegression & Multitarget Regression & \community & Community \\",
        r"\MultitargetClassification & Multitarget Classification & \research & Research \\",
        r"\bottomrule",
        r"\end{tabular}",
        r"\end{table}",
        "",
        r"\begin{longtable}{" + "\n  ".join(colspec) + "}",
        r"\caption{\textbf{List of the Kaggle competitions included in our benchmark.} Each row represents a Kaggle competition, showing its Kaggle ID (first column), its type, its category on Kaggle, the input modalities it involve,  the number of submissions that can be retained for the final scoring (\#Select Subs), and the number of  teams that participated in this competition. Note that the column \# Select Subs corresponds to $k_c$ in equation~\eqref{eq:calquantile}. See Table \ref{tab:symbol-legend} for the symbols appearing in the Competition Type and Kaggle Type columns.} \\",
        r"\hline\hline",
        " & ".join(headers) + r" \\",
        r"\hline\hline",
        r"\endfirsthead",
        r"\hline\hline",
        " & ".join(headers) + r" \\",
        r"\hline\hline",
        r"\endhead"
    ]

    for row in competition_data:
        cells = []
        for key in cols:
            if key == "CompetitionType":
                cells.append(rf"\{row[key]}")
            elif key == "TaskType":
                if row[key] == "RegressionandBinaryClassification":
                    cells.append(r"\Regression \BinaryClassification")
                else:
                    cells.append(rf"\{row[key]}")
            elif key == "MaxSubmissions":
                if row[key] >= 100:
                    cells.append(r"$\geq 100$")
                else:
                    cells.append(str(row[key]))
            else:
                cells.append(str(row[key]))
        latex_lines.append(" & ".join(cells) + r" \\")

    latex_lines.append(r"\end{longtable}")
    latex_lines.append(r"\hline")
    latex_lines.append(r"\vspace{0.5em}")

    return "\n".join(latex_lines)
